/* ==== Print Format Styles Start (Affecting the printed/pdf report) === */
  .print-format {
    /* Margin should be separate because frappe is reading styles like this */
    margin-left: 5mm;
    margin-right: 5mm;
    margin-top: 10mm;
    margin-bottom: 0mm;
    font-size: 7px !important;
    font-family: "Readex Pro", sans-serif;
  }

  /* Override the existing styles */
  .print-format td img {
    max-height: 50px;
    max-width: 100%;
    height: auto !important;
    width: auto !important;
    object-fit: contain;
    display: block;
    margin: auto; 
  }
  /* === Print Format Styles End === */

  .attendance-table {
    width: 100%;
    border-collapse: collapse;
    table-layout: fixed;
    border: 1px solid #333;
  }

  .attendance-table th,
  .attendance-table td {
    border: 1px solid #333;
    padding: 4px !important;
    text-align: center !important;
    vertical-align: middle !important;
  }

  .attendance-table .empty-attendance-cell {
    background-color: #b9b9b9;
  }

  .section-header {
    font-weight: bold;
    text-align: left;
  }

  .title-section td {
    font-family: "Cairo", sans-serif !important;
    border: none !important;
    font-size: 18px !important;
    font-weight: bold !important;
    font-style: italic !important;
    text-align: center;
    color: black;
  }

  .title-section .logo-cell {
    padding: 10px !important;
  }

  .meta-cell {
    text-align: left;
    font-size: 10px;
  }

  .title-section,
  .meta-section,
  .header-section td,
  .staff-duty th {
    background-color: #f5f5f5;
  }

  .signatures td {
    height: 50px !important;
  }

  .stamps td {
    height: 70px !important;
  }

  .legend span {
    border-left: 2px solid #000;
    padding-right: 12px;
    padding-left: 5px;
    margin-right: 3px;
  }

  @media print {
    .attendance-page {
      page-break-after: always;
    }
    .attendance-page:not(:first-child) { /* Because first one is alreading getting the margin from print format margin's above */
      margin-top: 10mm !important;
    }
  }
